parameters.functionCode:
const body = $json.body;
const customer = body.customer || {};
const listing = body.listing || {};
const timing = body.timing || {};
const access = body.access || {};
const services = body.services || {};
const estimate = body.estimate || {};
const flags = body.flags || {};
const meta = body.meta || {};

// Build reusable variables
const clientFullName = `${customer.firstName || ''} ${customer.lastName || ''}`.trim();
const servicesText = Array.isArray(services.selected) ? services.selected.join(', ') : (services.selected || '');
const viewsText = Array.isArray(services.views) ? services.views.join(', ') : (services.views || '');
const subject = `Photo Request: ${listing.address || 'Unknown Address'}`;
const internalSubject = `New Photo Request: ${listing.address || 'Unknown'} - ${clientFullName}`;
const submittedAt = meta.submittedAt || new Date().toISOString();
const requestId = meta.requestId || meta.jobId || '';
const sourceSystem = meta.source || 'romwebsite2026';

// Agency-based recipient routing
const agencyName = (customer.agency || '').trim();
const penFedAgencies = ['PenFed Gallo Realty', 'LeeAnn Group'];
const includePenFed = penFedAgencies.includes(agencyName);

// Build internal recipient list
const internalRecipients = ['ryan@ryanowenphotography.com'];
if (includePenFed) {
  internalRecipients.push('rehoboth@penfedrealty.com');
}

// Formatted estimate block
const lineItemsText = estimate.lineItemsText || '';
const estimatedTotal = estimate.estimatedTotal || estimate.subtotal || 0;

return [{
  json: {
    // Original payload preserved
    ...body,
    // Computed variables for downstream nodes
    _vars: {
      clientFullName,
      servicesText,
      viewsText,
      subject,
      internalSubject,
      submittedAt,
      requestId,
      sourceSystem,
      internalRecipients,
      includePenFed,
      lineItemsText,
      estimatedTotal,
      agencyName,
      // Passthrough convenience aliases
      customer,
      listing,
      timing,
      access,
      services,
      estimate,
      flags,
      meta
    }
  }
}];

